prompt --application/shared_components/logic/application_processes/carregar_nome_usuario
begin
wwv_flow_imp_shared.create_flow_process(
 p_id=>wwv_flow_imp.id(248699588934224187)
,p_process_sequence=>1
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Carregar_nome_usuario'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_cpf dda.vinculo_sf.num_cpf%TYPE;',
'BEGIN',
unistr('    -- Verifica se o login \00E9 CPF (s\00F3 n\00FAmeros) ou e-mail'),
'    IF REGEXP_LIKE(:APP_USER, ''^\d+$'') THEN',
'        v_cpf := :APP_USER;',
'    ELSE',
'        SELECT u.num_cpf_pessoa',
'          INTO v_cpf',
'          FROM dda.usuario_rede u',
'         WHERE LOWER(u.txt_email_sf) = LOWER(:APP_USER) || ''@senado.leg.br'';',
'    END IF;',
'',
unistr('    -- Busca o nome formatado e atribui ao item da p\00E1gina'),
'    SELECT UPPER(',
'               SUBSTR(',
'                 TRANSLATE(v.nom_pessoa,',
unistr('                   ''\00C1\00C0\00C2\00C3\00C4\00C9\00C8\00CA\00CB\00CD\00CC\00CE\00CF\00D3\00D2\00D4\00D5\00D6\00DA\00D9\00DB\00DC\00C7\00E1\00E0\00E2\00E3\00E4\00E9\00E8\00EA\00EB\00ED\00EC\00EE\00EF\00F3\00F2\00F4\00F5\00F6\00FA\00F9\00FB\00FC\00E7'','),
'                   ''AAAAAEEEEIIIIOOOOOUUUUCaaaaaeeeeiiiiooooouuuuc''),',
'                 1,',
'                 INSTR(v.nom_pessoa, '' '') - 1',
'               )',
'           ) || '' ('' || v.num_cpf || '')''',
'      INTO :NOME_USUARIO',
'      FROM dda.vinculo_sf v',
'     WHERE v.num_cpf = v_cpf',
'       AND ROWNUM = 1;',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
unistr('        :NOME_USUARIO := ''USU\00C1RIO N\00C3O ENCONTRADO'';'),
'    WHEN OTHERS THEN',
'        :NOME_USUARIO := ''ERRO: '' || SQLERRM;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_version_scn=>508590202618
);
end;
