wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(232758568374312313)
,p_plug_name=>'Ordens de Servico'
,p_region_name=>'os_todos'
,p_parent_plug_id=>wwv_flow_imp.id(232758314039312311)
,p_region_template_options=>'#DEFAULT#:t-Region--removeHeader js-removeLandmark:t-Region--scrollBody'
,p_plug_template=>wwv_flow_imp.id(245793973035224004)
,p_plug_display_sequence=>30
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_html CLOB := '''';',
'    v_tem_registro  BOOLEAN := FALSE;',
'BEGIN',
'    v_html := v_html || ''',
'        <div class="os-list" ',
'             style="font-family:Arial, sans-serif;',
'                    max-height:500px;',
'                    overflow-y:auto;',
'                    border:1px solid #ddd;',
'                    border-radius:6px;">'';',
'',
'    FOR r IN (',
'        SELECT ',
'            o.id_os,',
'            o.num_os,',
'            o.solicitante,',
'            o.assunto,',
'            o.dat_solicitacao,',
'            o.categoria,',
'            o.setor,',
'            COUNT(i.num_img) AS qtd_imgs',
'        FROM ordens_servicos o',
'        LEFT JOIN img_ordens_servicos i ',
'            ON o.id_os = i.fk_ordens_servicos',
'        WHERE ',
'              (:P1_PESQUISA_NUM IS NULL OR ',
'                 LOWER(TRANSLATE(o.num_os,',
unistr('                   ''\00C1\00C0\00C2\00C3\00C4\00C9\00C8\00CA\00CB\00CD\00CC\00CE\00CF\00D3\00D2\00D4\00D5\00D6\00DA\00D9\00DB\00DC\00C7\00E1\00E0\00E2\00E3\00E4\00E9\00E8\00EA\00EB\00ED\00EC\00EE\00EF\00F3\00F2\00F4\00F5\00F6\00FA\00F9\00FB\00FC\00E7'','),
'                   ''AAAAAEEEEIIIIOOOOOUUUUCaaaaaeeeeiiiiooooouuuuc'')) ',
'                 LIKE ''%'' || LOWER(TRANSLATE(:P1_PESQUISA_NUM,',
unistr('                   ''\00C1\00C0\00C2\00C3\00C4\00C9\00C8\00CA\00CB\00CD\00CC\00CE\00CF\00D3\00D2\00D4\00D5\00D6\00DA\00D9\00DB\00DC\00C7\00E1\00E0\00E2\00E3\00E4\00E9\00E8\00EA\00EB\00ED\00EC\00EE\00EF\00F3\00F2\00F4\00F5\00F6\00FA\00F9\00FB\00FC\00E7'','),
'                   ''AAAAAEEEEIIIIOOOOOUUUUCaaaaaeeeeiiiiooooouuuuc'')) || ''%'')',
'          AND (:P1_PESQUISA_ASSUNTO IS NULL OR ',
'                 LOWER(TRANSLATE(o.assunto,',
unistr('                   ''\00C1\00C0\00C2\00C3\00C4\00C9\00C8\00CA\00CB\00CD\00CC\00CE\00CF\00D3\00D2\00D4\00D5\00D6\00DA\00D9\00DB\00DC\00C7\00E1\00E0\00E2\00E3\00E4\00E9\00E8\00EA\00EB\00ED\00EC\00EE\00EF\00F3\00F2\00F4\00F5\00F6\00FA\00F9\00FB\00FC\00E7'','),
'                   ''AAAAAEEEEIIIIOOOOOUUUUCaaaaaeeeeiiiiooooouuuuc'')) ',
'                 LIKE ''%'' || LOWER(TRANSLATE(:P1_PESQUISA_ASSUNTO,',
unistr('                   ''\00C1\00C0\00C2\00C3\00C4\00C9\00C8\00CA\00CB\00CD\00CC\00CE\00CF\00D3\00D2\00D4\00D5\00D6\00DA\00D9\00DB\00DC\00C7\00E1\00E0\00E2\00E3\00E4\00E9\00E8\00EA\00EB\00ED\00EC\00EE\00EF\00F3\00F2\00F4\00F5\00F6\00FA\00F9\00FB\00FC\00E7'','),
'                   ''AAAAAEEEEIIIIOOOOOUUUUCaaaaaeeeeiiiiooooouuuuc'')) || ''%'')',
'          AND (:P1_SOLICITANTE IS NULL OR',
'                    LOWER(o.solicitante) = LOWER(:P1_SOLICITANTE))',
'          AND (',
'              (:P1_DAT_INICIO IS NULL AND :P1_DAT_FIM IS NULL)',
'              OR (:P1_DAT_INICIO IS NULL AND o.dat_solicitacao <= :P1_DAT_FIM)',
'              OR (:P1_DAT_FIM IS NULL AND o.dat_solicitacao >= :P1_DAT_INICIO)',
'              OR (o.dat_solicitacao BETWEEN :P1_DAT_INICIO AND :P1_DAT_FIM)',
'          )',
'          AND (',
'              :P1_CATEGORIA IS NULL',
'              OR (',
'                  :P1_CATEGORIA IS NOT NULL',
'                  AND :P1_INSTALACAO IS NULL',
'                  AND LOWER(o.categoria) LIKE LOWER(''%'' || :P1_CATEGORIA || ''%'')',
'              ) ',
'              OR (',
'                  :P1_CATEGORIA IS NOT NULL',
'                  AND :P1_INSTALACAO IS NOT NULL',
'                  AND LOWER(o.categoria) = LOWER(:P1_CATEGORIA || '' --> '' || :P1_INSTALACAO)',
'              )',
'          )',
'          AND (',
'              :P1_SETOR IS NULL',
'              OR (LOWER(o.setor) = LOWER(:P1_SETOR))',
'          )',
'        GROUP BY o.id_os, o.num_os, o.solicitante, o.assunto, o.dat_solicitacao, o.categoria, o.setor',
'        ORDER BY o.dat_solicitacao DESC, o.id_os DESC',
'    ) LOOP',
'        BEGIN',
'            v_tem_registro := TRUE;',
'            v_html := v_html || ''',
'                <div class="os-item"',
'                     id="os_'' || TO_CHAR(r.id_os) || ''" ',
'                     style="display:flex;',
'                            justify-content:space-between;',
'                            align-items:center;',
'                            padding:10px;',
'                            border-bottom:1px solid #eee;">',
'                    <div class="os-content">',
'                        <div style="font-size:18px;font-weight:bold;color:#2c3e50;">'' || r.num_os || '' - '' || r.categoria || ''</div>',
'                        <div style="font-size:14px;color:#555;margin-top:2px;">'' || r.assunto || ''</div>',
'                        <div style="display:flex;justify-content:space-between;',
'                                    font-size:12px;color:#888;margin-top:2px;">',
'                            <span>'' || TO_CHAR(r.dat_solicitacao, ''DD/MM/YYYY HH24:MI'') || ''</span>',
'                            <span>'' || r.solicitante || ''</span>',
'                        </div>',
'                    </div>',
'                    <div style="font-size:20px;color:#bbb;"> ',
'                        <a class=''''os-link'''' href="'' || APEX_PAGE.GET_URL( p_page => 1, p_items => ''P1_ID_OS,P1_EXIBIR'', p_values => r.id_os || '','' || r.num_os) || ''">&rsaquo; </a>',
'                    </div>',
'                </div>'';',
'        END;',
'    END LOOP;',
'',
'    IF NOT v_tem_registro THEN',
'        v_html := v_html || ''',
'            <div style="padding:20px;',
'                        text-align:center;',
'                        color:#888;',
'                        font-style:italic;">',
unistr('                Nenhuma Ordem de Servi\00E7o encontrada para esses filtros combinados.'),
'            </div>'';',
'    END IF;',
'',
'    v_html := v_html || ''</div>'';',
'',
'    RETURN v_html;',
'END;',
''))
,p_lazy_loading=>true
,p_plug_source_type=>'NATIVE_DYNAMIC_CONTENT'
,p_ajax_items_to_submit=>'P1_PESQUISA_NUM,P1_PESQUISA_ASSUNTO,P1_SOLICITANTE,P1_DAT_INICIO,P1_DAT_FIM,P1_CATEGORIA,P1_INSTALACAO,P1_SETOR'
);
