wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(247271517390253438)
,p_plug_name=>'Detalhes'
,p_region_name=>'Detalhes'
,p_parent_plug_id=>wwv_flow_imp.id(247272254292253445)
,p_region_css_classes=>'detalhes-altos'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_plug_template=>wwv_flow_imp.id(245793973035224004)
,p_plug_display_sequence=>40
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_num_os        ordens_servicos.num_os%TYPE;',
'    v_solicitante   ordens_servicos.solicitante%TYPE;',
'    v_obs           ordens_servicos.obs%TYPE;',
'    v_cat           ordens_servicos.categoria%TYPE;',
'    v_dat_sol       ordens_servicos.dat_solicitacao%TYPE;',
'    v_assunto       ordens_servicos.assunto%TYPE;',
'    v_html          CLOB := '''';',
'BEGIN',
unistr('    SELECT num_os, solicitante, NVL(obs,''N\00E3o h\00E1.''), dat_solicitacao, assunto, categoria'),
'      INTO v_num_os, v_solicitante, v_obs, v_dat_sol, v_assunto, v_cat',
'      FROM ordens_servicos',
'     WHERE id_os = :P1_ID_OS;',
'',
'    -- layout em duas colunas',
'    v_html := v_html || ''<div style="display:flex;justify-content:space-between;gap:40px;">'';',
'',
'    -- coluna esquerda',
'    v_html := v_html || ''<div style="flex:1;">'' ||',
unistr('                       ''<div><b>N\00FAmero da Ordem de Servi\00E7o</b><br>''||v_num_os||''</div><br>'' ||'),
'                       ''<div><b>Solicitante</b><br>''||v_solicitante||''</div><br>'' ||',
unistr('                       ''<div><b>Observa\00E7\00E3o</b><br>''||v_obs||''</div><br>'' ||'),
'                       ''<div><b>Categoria</b><br>''||v_cat||''</div><br>'' ||',
'                       ''</div>'';',
'',
'    -- coluna direita',
'    v_html := v_html || ''<div style="flex:1;">'' ||',
unistr('                       ''<div><b>Data de Solicita\00E7\00E3o</b><br>''||'),
'                       TO_CHAR(v_dat_sol,''DD/MM/YYYY HH24:MI'')||''</div><br>'' ||',
unistr('                       ''<div><b>Assunto da Solicita\00E7\00E3o</b><br>''||v_assunto||''</div><br>'' ||'),
'                       ''</div>'';',
'',
'    v_html := v_html || ''</div>'';',
'',
'    RETURN v_html;',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'    RETURN ''',
'        <div style="padding:20px;',
'                    text-align:center;',
'                    color:#888;',
'                    font-style:italic;',
'                    font-family:Arial, sans-serif;',
'                    border:1px solid #ddd;',
'                    border-radius:6px;',
'                    background-color:#fafafa;">',
unistr('            Selecione uma Ordem de Servi\00E7o.'),
'        </div>'';',
'END;',
''))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_DYNAMIC_CONTENT'
,p_ajax_items_to_submit=>'P1_ID_OS'
);
