,p_name=>'P2_CRIADO'
,p_item_sequence=>30
,p_item_plug_id=>wwv_flow_imp.id(232761603670312344)
,p_use_cache_before_default=>'NO'
,p_item_default=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_count NUMBER;',
'BEGIN',
'    IF :P2_NUM_OS IS NULL THEN',
'        RETURN ''N'';',
'    END IF;',
'',
'    SELECT COUNT(*) ',
'      INTO v_count',
'      FROM ordens_servicos',
'     WHERE num_os = :P2_NUM_OS;',
'',
'    IF v_count > 0 THEN',
'        RETURN ''S'';',
'    ELSE',
'        RETURN ''N'';',
'    END IF;',
'END;',
''))
,p_item_default_type=>'FUNCTION_BODY'
,p_item_default_language=>'PLSQL'
,p_display_as=>'NATIVE_HIDDEN'
