'  BEGIN',
'    SELECT COUNT(*) INTO v_count',
'    FROM ordens_servicos',
'    WHERE num_os = :P2_NUM_OS;',
'  EXCEPTION WHEN OTHERS THEN',
'    v_count := 0;',
'  END;',
'',
'  IF v_count > 0 THEN',
'    :P2_CRIADO := ''S'';',
'  ELSE',
'    :P2_CRIADO := ''N'';',
'  END IF;',
'END;',
''))
