wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(232760696061312334)
,p_process_sequence=>10
,p_process_point=>'ON_SUBMIT_BEFORE_COMPUTATION'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Criar OS'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_obs   VARCHAR2(4000);',
'    v_id_os ordens_servicos.id_os%TYPE;',
'BEGIN',
unistr('    v_obs := NVL(:P2_OBS, ''N\00E3o h\00E1.'');'),
'',
unistr('    -- Verifica se a categoria \00E9 "Instala\00E7\00F5es prediais"'),
unistr('    IF :P2_CATEGORIA = ''Instala\00E7\00F5es prediais'' THEN'),
'        IF :P2_INSTALACOES IS NULL THEN',
'            apex_error.add_error(',
unistr('                p_message => ''Para categoria "Instala\00E7\00F5es prediais", o campo Instala\00E7\00F5es n\00E3o pode ser vazio.'','),
'                p_display_location => apex_error.c_inline_in_notification',
'            );',
'            RETURN;',
'        END IF;',
'',
'        INSERT INTO ordens_servicos (',
'            num_os,',
'            dat_solicitacao,',
'            solicitante,',
'            assunto,',
'            obs,',
'            categoria,',
'            setor',
'        ) VALUES (',
'            :P2_NUM_OS,',
'            :P2_DAT_SOLICITACAO,',
'            :P2_SOLICITANTE,',
'            :P2_ASSUNTO,',
'            v_obs,',
'            :P2_CATEGORIA || '' --> '' || :P2_INSTALACOES,',
'            :P2_SETOR',
'        )',
'        RETURNING id_os INTO v_id_os;',
'    ELSE',
'        -- Para outras categorias, insere apenas a categoria',
'        INSERT INTO ordens_servicos (',
'            num_os,',
'            dat_solicitacao,',
'            solicitante,',
'            assunto,',
'            obs,',
'            categoria,',
'            setor',
'        ) VALUES (',
'            :P2_NUM_OS,',
'            :P2_DAT_SOLICITACAO,',
'            :P2_SOLICITANTE,',
'            :P2_ASSUNTO,',
'            v_obs,',
'            :P2_CATEGORIA,',
'            :P2_SETOR',
'        )',
'        RETURNING id_os INTO v_id_os;',
'    END IF;',
'',
'    FOR img_rec IN (',
'        SELECT arq, mimetype, filename',
'        FROM tmp_ordens_servicos',
'        WHERE cpf_solicitante = :P2_CPF',
'    ) LOOP',
'        INSERT INTO img_ordens_servicos (',
'            fk_ordens_servicos,',
'            arq,',
'            mimetype,',
'            filename',
'        ) VALUES (',
'            v_id_os,',
'            img_rec.arq,',
'            img_rec.mimetype,',
'            img_rec.filename',
'        );',
'    END LOOP;',
'',
'    DELETE FROM tmp_ordens_servicos',
'    WHERE cpf_solicitante = :P2_CPF;',
'',
'    :P2_ID_OS := v_id_os;',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>232760696061312334
);
end;
