 p_id=>wwv_flow_imp.id(268337240386430429)
,p_chart_id=>wwv_flow_imp.id(268337139021430428)
,p_seq=>10
,p_name=>unistr('Qtd por M\00EAs')
,p_data_source_type=>'FUNC_BODY_RETURNING_SQL'
,p_function_body_language=>'PLSQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_sql   CLOB;',
'    v_solicitantes  VARCHAR2(4000);',
'    v_categorias    VARCHAR2(4000);',
'BEGIN',
'    IF :P4_SOLICITANTE IS NOT NULL THEN',
'        v_solicitantes := '''''''' || REPLACE(:P4_SOLICITANTE, '':'', '''''','''''') || '''''''';',
'    END IF;',
'',
'    IF :P4_CATEGORIA IS NOT NULL THEN',
'        v_categorias := '''''''' || REPLACE(:P4_CATEGORIA, '':'', '''''','''''') || '''''''';',
'    END IF;',
'',
'    v_sql := ''',
'        WITH MESES AS (',
'            SELECT',
'                RTRIM(TO_CHAR(ADD_MONTHS(TRUNC(SYSDATE, ''''YEAR''''), LEVEL - 1), ',
'                    ''''MONTH'''', ''''NLS_DATE_LANGUAGE=PORTUGUESE'''')) || ''''/'''' ||',
'                    TO_CHAR(ADD_MONTHS(TRUNC(SYSDATE, ''''YEAR''''), LEVEL - 1), ''''YYYY'''') AS MES',
'            FROM DUAL',
'            CONNECT BY LEVEL <= 12',
'        ),',
'        OS_AGRUPADAS AS (',
'            SELECT',
'                RTRIM(TO_CHAR(os.dat_solicitacao, ''''MONTH'''', ''''NLS_DATE_LANGUAGE=PORTUGUESE'''')) || ''''/'''' ||',
'                    TO_CHAR(os.dat_solicitacao, ''''YYYY'''') AS MES,',
'                COUNT(*) AS QTD',
'            FROM ordens_servicos os',
'            WHERE 1 = 1 '';',
'    ',
'    IF :P4_INICIO IS NOT NULL THEN',
'        v_sql := v_sql || '' AND os.dat_solicitacao >= :P4_INICIO'';',
'    END IF;',
'',
'    IF :P4_FIM IS NOT NULL THEN',
'        v_sql := v_sql || '' AND os.dat_solicitacao <= :P4_FIM'';',
'    END IF;',
'',
'    IF v_solicitantes IS NOT NULL THEN',
'        v_sql := v_sql || '' AND os.solicitante IN ('' || v_solicitantes || '')'';',
'    END IF;',
'',
'    IF v_categorias IS NOT NULL THEN',
'        v_sql := v_sql || '' AND os.categoria IN ('' || v_categorias || '')'';',
'    END IF;',
'',
'    IF :P4_SETOR <> ''ASQUALOG'' THEN',
'        v_sql := v_sql || '' AND os.setor = :P4_SETOR'';',
'    END IF;',
'',
'    v_sql := v_sql || ''',
'            GROUP BY RTRIM(TO_CHAR(os.dat_solicitacao, ''''MONTH'''', ''''NLS_DATE_LANGUAGE=PORTUGUESE'''')) || ''''/'''' ||',
'                     TO_CHAR(os.dat_solicitacao, ''''YYYY'''')',
'        )',
'        SELECT',
'            m.mes AS label,',
'            NVL(r.qtd, 0) AS value,',
unistr('            ''''Ordens de Servi\00E7o'''' AS series'),
'        FROM meses m',
'        LEFT JOIN os_agrupadas r ON m.mes = r.mes',
'        ORDER BY TO_DATE(m.mes, ''''MONTH/YYYY'''', ''''NLS_DATE_LANGUAGE=PORTUGUESE'''')',
'    '';',
'    /* Mostrar apenas os meses com ordens',
'    SELECT',
'        r.mes AS label,',
'        NVL(r.qtd, 0) AS value,',
unistr('        ''''Ordens de Servi\00E7o'''' AS series'),
'    FROM os_agrupadas r',
'    ORDER BY TO_DATE(r.mes, ''''MM/YYYY'''')',
'    */',
'    RETURN v_sql;',
'END;',
''))
,p_ajax_items_to_submit=>'P4_INICIO,P4_FIM,P4_SETOR,P4_SOLICITANTE,P4_CATEGORIA'
,p_series_name_column_name=>'SERIES'
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'LABEL'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>true
,p_items_label_position=>'outsideBarEdge'
);
